#include <stdio.h>
#include <stdlib.h>

// Fenwick tree
static int *bit;
int N;
void bit_add(int idx, int val){ for(++idx; idx<=N; idx+=idx&-idx) bit[idx-1]+=val; }
int bit_sum(int idx){ int s=0; for(++idx; idx>0; idx-=idx&-idx) s+=bit[idx-1]; return s; }
int bit_range_sum(int l,int r){ if(l>r) return 0; return bit_sum(r)- (l?bit_sum(l-1):0); }

int cmp_idx(const void *a,const void *b){
    int i=*(const int*)a, j=*(const int*)b;
    // simulate compare i j by reading the permutation (offline version)
    extern int *perm; // defined in main
    return perm[i]-perm[j];
}

int main(){
    if(scanf("%d",&N)!=1) return 0;
    int *perm=malloc(N*sizeof(int));
    for(int i=0;i<N;i++) scanf("%d",&perm[i]);
    int flag; scanf("%d",&flag);
    // sort indices by hidden value using compare
    int *idx=malloc(N*sizeof(int));
    for(int i=0;i<N;i++) idx[i]=i;
    qsort(idx,N,sizeof(int),cmp_idx);
    // rank[i] = Fi
    int *rank=malloc(N*sizeof(int));
    for(int pos=0;pos<N;pos++) rank[idx[pos]]=pos; // because permutation is 0..N-1
    // BIT for inversion count
    bit=calloc(N+1,sizeof(int));
    long long inv=0;
    for(int i=0;i<N;i++){
        int v=rank[i];
        inv+=bit_range_sum(v+1,N-1);
        bit_add(v,1);
    }
    // output the required sequence of calls
    printf("1\nput %lld\n",inv);
    return 0;
}

