#include <bits/stdc++.h>
using namespace std;

struct BIT{
    int n; vector<int> t;
    BIT(int n=0):n(n),t(n+1,0){}
    void add(int idx,int val){ for(++idx; idx<=n; idx+=idx&-idx) t[idx]+=val; }
    int sum(int idx){ int s=0; for(++idx; idx>0; idx-=idx&-idx) s+=t[idx]; return s; }
    int rangeSum(int l,int r){ if(l>r) return 0; return sum(r)-(l?sum(l-1):0); }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N; if(!(cin>>N)) return 0;
    vector<int> a(N);
    for(int &x:a) cin>>x;
    int flag; cin>>flag;
    // sort indices using the real values (offline simulation of compare)
    vector<int> idx(N);
    iota(idx.begin(), idx.end(), 0);
    sort(idx.begin(), idx.end(), [&](int i,int j){ return a[i] < a[j]; });
    vector<int> rank(N);
    for(int pos=0; pos<N; ++pos) rank[idx[pos]] = pos; // value == rank
    BIT bit(N);
    long long inv=0;
    for(int i=0;i<N;++i){
        int v=rank[i];
        inv += bit.rangeSum(v+1, N-1);
        bit.add(v,1);
    }
    cout<<1<<"\n"<<"put "<<inv<<"\n";
    return 0;
}

