import java.io.*;
import java.util.*;

public class Main {
    static class BIT {
        int n; int[] t;
        BIT(int n){ this.n=n; t=new int[n+1]; }
        void add(int idx,int val){ for(++idx; idx<=n; idx+=idx&-idx) t[idx]+=val; }
        int sum(int idx){ int s=0; for(++idx; idx>0; idx-=idx&-idx) s+=t[idx]; return s; }
        int rangeSum(int l,int r){ if(l>r) return 0; return sum(r)-(l>0?sum(l-1):0); }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int N = Integer.parseInt(br.readLine().trim());
        int[] a = new int[N];
        st = new StringTokenizer(br.readLine());
        for(int i=0;i<N;i++) a[i]=Integer.parseInt(st.nextToken());
        int flag = Integer.parseInt(br.readLine().trim());
        Integer[] idx = new Integer[N];
        for(int i=0;i<N;i++) idx[i]=i;
        Arrays.sort(idx, (i,j)->Integer.compare(a[i], a[j]));
        int[] rank = new int[N];
        for(int pos=0; pos<N; ++pos) rank[idx[pos]] = pos;
        BIT bit = new BIT(N);
        long inv = 0;
        for(int i=0;i<N;i++){
            int v = rank[i];
            inv += bit.rangeSum(v+1, N-1);
            bit.add(v,1);
        }
        StringBuilder sb = new StringBuilder();
        sb.append(1).append('\n');
        sb.append("put ").append(inv).append('\n');
        System.out.print(sb.toString());
